const https = require('https');

// Input: { urls: ["https://docs.gostoa.dev/blog/slug1", ...], source, run_id }
const { urls, source, run_id } = $input.first().json.body;

if (!urls || !Array.isArray(urls) || urls.length === 0) {
  return [{ json: { status: 'skipped', reason: 'no URLs provided' } }];
}

function httpsRequest(options, body) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => resolve({ statusCode: res.statusCode, body: data }));
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

// --- Google Indexing API ---
// Requires GOOGLE_INDEXING_API_KEY or OAuth2 service account token.
// For service accounts: use n8n's Google credentials (OAuth2) and swap
// this Code node for the built-in HTTP Request with Google OAuth2.
const apiKey = $env.GOOGLE_INDEXING_API_KEY || '';
const indexResults = [];

if (apiKey) {
  for (const url of urls) {
    try {
      const payload = JSON.stringify({ url, type: 'URL_UPDATED' });
      const res = await httpsRequest({
        hostname: 'indexing.googleapis.com',
        path: `/v3/urlNotifications:publish?key=${apiKey}`,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(payload)
        }
      }, payload);
      indexResults.push({ url, status: res.statusCode, ok: res.statusCode === 200 });
    } catch (e) {
      indexResults.push({ url, status: 'error', error: e.message });
    }
  }
} else {
  // No API key — skip indexing, still send Slack notification
  for (const url of urls) {
    indexResults.push({ url, status: 'skipped', reason: 'GOOGLE_INDEXING_API_KEY not configured' });
  }
}

// --- Slack Notification ---
const slackWebhook = $env.SLACK_CONTENT_WEBHOOK || $env.SLACK_WEBHOOK_URL || '';

if (slackWebhook) {
  const links = urls.map(u => {
    const slug = u.split('/blog/')[1] || u;
    return `• <${u}|${slug}>`;
  }).join('\n');

  const indexed = indexResults.filter(r => r.ok).length;
  const indexStatus = apiKey
    ? ` | Google Indexing: ${indexed}/${urls.length} submitted`
    : '';

  const text = `:pencil: *${urls.length} Blog Post(s) Published*\n${links}\n\n_Source: ${source || 'manual'}${indexStatus}_`;

  try {
    const { hostname, pathname } = new URL(slackWebhook);
    const payload = JSON.stringify({ text });
    await httpsRequest({
      hostname,
      path: pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload)
      }
    }, payload);
  } catch (e) {
    // Slack notification failure is non-blocking
  }
}

return [{ json: {
  status: 'ok',
  urls_processed: urls.length,
  index_results: indexResults,
  slack_sent: !!slackWebhook,
  source: source || 'manual',
  run_id: run_id || null
} }];
